const items = $input.all();

// Filtro per punteggio (già calcolato nel nodo precedente)
const results = items.filter(item => item.json.ai_score >= 6);

// Dedup nel batch
const seen = new Set();
return results.filter(item => {
  const id = String(item.json.job_id);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const queries = [
/**
 'data', 'analyst', 'scientist', 'engineer', 'risk', 'modelling', 'specialist', 'sustainability', 'environmental', 'actuarial', 'quantitative',
  'data scientist',
  'catastrophe',
  'machine learning',
  'reinsurance',
  'agricultural',* 
 */
  'climate'
];

return queries.map(q => ({ json: { query: q } }));

const items = $input.all();

if (items.length === 0) {
  return []; 
}

let emailHtml = "<h2>Ecco i nuovi annunci di lavoro trovati:</h2><ul>";

for (const item of items) {
  const job_title = item.json.job_title || "Titolo non specificato";
  const company = item.json.company || "Azienda non specificata";
  const url = item.json.url || "#";
  const ai_score = item.json.ai_score !== undefined ? item.json.ai_score : "N/A";
  const ai_category = item.json.ai_category || "";

  emailHtml += `<li><strong>${job_title}</strong> (${company}) — Score: ${ai_score} [${ai_category}] - <a href="${url}">Link all'annuncio</a></li>`;
}

emailHtml += "</ul><br><p>Buona giornata!</p>";

return [{
  json: {
    emailBody: emailHtml
  }
}];

const original = $('Loop Over Items1').item.json;
const aiRaw = $input.item.json;

let parsed;
try {
  const raw = (aiRaw.content?.parts?.[0]?.text || '')
    .replace(/```json|```/g, '')
    .trim();
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { punteggio: 0, categoria: 'N/A', motivazione: 'AI parsing failed' };
}

return {
  json: {
    ...original,
    ai_score: parsed.punteggio,
    ai_category: parsed.categoria,
    ai_reason: parsed.motivazione
  }
};

const acadFields = [
  'physics',
  'mathematics-statistics-datascience',
  'computer-science',
  'earth-and-environmental-systems-sciences',
  'engineering'
];

return acadFields.map(f => ({
  json: { url: `https://acadjobs.com/${f}/ch/all-categories/all-job-types/all-levels` }
}));

const items = $input.all();
const jobs = [];

function clean(str) {
  return str
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

for (const item of items) {
  const html = item.json.data || item.json.body || '';
  const chunks = html.split('<div class="item"').slice(1);

  for (const chunk of chunks) {
    const tokenMatch = chunk.match(/token=([A-Za-z0-9_\-]+)"/);
    const titleMatch = chunk.match(/<a href="\/job\/\?token=[^"]+"[^>]*>([\s\S]*?)<\/a>/);
    const companyLocMatch = chunk.match(/<td style="text-align:left;font-size:12px">([\s\S]*?)<\/td>/);
    const publishedMatch = chunk.match(/Published:\s*([^']+)'/);
    const descMatches = [...chunk.matchAll(/<td\s+width="50%"\s+valign="top"\s+style="text-align:justify"\s*>([\s\S]*?)<\/td>/g)];

    if (!tokenMatch || !titleMatch) continue;

    const token = tokenMatch[1];
    let rawTitle = clean(titleMatch[1]);

    let countries = '';
    let title = rawTitle;
    const titleSplit = rawTitle.match(/^([a-z]{2}(?:,\s*[a-z]{2})*)\s*:\s*(.+)$/i);
    if (titleSplit) {
      countries = titleSplit[1].replace(/\s+/g, '');
      title = titleSplit[2].trim();
    }

    let company = '', location = '';
    if (companyLocMatch) {
      const parts = clean(companyLocMatch[1]).split(';');
      company = (parts[0] || '').trim();
      location = (parts.slice(1).join(';') || '').trim();
    }

    const description = descMatches.map(m => clean(m[1])).join(' | ');
    const published = publishedMatch ? publishedMatch[1].trim() : '';

    jobs.push({
      json: {
        job_id: token,
        job_title: title,
        countries,
        company,
        location,
        url: `https://acadjobs.com/job/?token=${token}`,
        published,
        description
      }
    });
  }
}

// Dedup: la stessa offerta può comparire in più field (physics, math, ecc.)
const seen = new Set();
return jobs.filter(item => {
  const id = String(item.json.job_id);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});
